package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Constructor;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_shouldReturnCSVParserInstance() throws IOException {
        String csvData = "a,b,c\n1,2,3\n4,5,6";
        Reader reader = new StringReader(csvData);

        CSVParser parser = csvFormat.parse(reader);

        assertNotNull(parser);
        // Since CSVParser constructor is called directly, check that parser has expected format and reader
        // We cannot access private fields, so just check class type
        assertEquals(CSVParser.class, parser.getClass());
    }

    @Test
    void testParse_withNullReader_shouldThrowNullPointerException() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParse_invokesCSVParserConstructor() throws Exception {
        Reader reader = new StringReader("a,b,c\n1,2,3");

        // Use reflection to create a spy of CSVParser when constructed via CSVFormat.parse
        CSVParser parserSpy = null;

        // Create a subclass of CSVFormat to override parse method to spy on CSVParser creation
        CSVFormat spyFormat = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeaderComments(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter()) {
            @Override
            public CSVParser parse(final Reader in) throws IOException {
                try {
                    Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class);
                    constructor.setAccessible(true);
                    CSVParser realParser = constructor.newInstance(in, this);
                    CSVParser spyParser = spy(realParser);
                    return spyParser;
                } catch (ReflectiveOperationException e) {
                    throw new IOException(e);
                }
            }
        };

        CSVParser parser = spyFormat.parse(reader);

        assertNotNull(parser);
        assertEquals(CSVParser.class, parser.getClass());
        verify(parser, atLeastOnce()).getFormat();
    }
}
